import os
import shutil
import time
from datetime import datetime
from flask import Flask, request, jsonify, send_file, abort
from functools import wraps
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Configuration
BASE_UPLOAD_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), 'user_uploads'))

# Ensure base upload directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a given user."""
    user_root = os.path.abspath(os.path.join(BASE_UPLOAD_DIR, str(user_id)))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def resolve_path(user_root, relative_path):
    """
    Safely resolve a relative path within the user's root directory.
    Uses os.path.join and os.path.normpath to construct and normalize the path.
    Prevents directory traversal attacks by ensuring the resolved path
    stays within the user's root directory.
    """
    if relative_path is None:
        relative_path = ''

    # Strip leading separators to treat as relative
    relative_path = relative_path.lstrip('/')
    relative_path = relative_path.lstrip('\\')

    # Join the user root with the relative path
    joined_path = os.path.join(user_root, relative_path)

    # Normalize the path to resolve '..' and other components
    normalized_path = os.path.normpath(joined_path)

    # Security check: ensure the normalized path is within the user's root
    abs_user_root = os.path.abspath(user_root)
    abs_normalized = os.path.abspath(normalized_path)

    if not abs_normalized.startswith(abs_user_root):
        return None  # Path traversal attempt detected

    return abs_normalized


def require_user_id(f):
    """Decorator to extract and validate user_id from request headers or query params."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        user_id = request.headers.get('X-User-ID') or request.args.get('user_id')
        if not user_id:
            return jsonify({'error': 'User ID is required. Provide X-User-ID header or user_id query parameter.'}), 401
        # Sanitize user_id
        user_id = secure_filename(str(user_id))
        if not user_id:
            return jsonify({'error': 'Invalid User ID.'}), 400
        kwargs['user_id'] = user_id
        return f(*args, **kwargs)
    return decorated_function


def get_file_info_dict(file_path, user_root):
    """Get detailed information about a file or directory."""
    stat = os.stat(file_path)
    rel_path = os.path.relpath(file_path, user_root)
    if rel_path == '.':
        rel_path = '/'

    info = {
        'name': os.path.basename(file_path) or '/',
        'path': '/' + rel_path if not rel_path.startswith('/') and rel_path != '/' else rel_path,
        'is_directory': os.path.isdir(file_path),
        'size_bytes': stat.st_size if not os.path.isdir(file_path) else None,
        'created': datetime.fromtimestamp(stat.st_ctime).isoformat(),
        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
        'accessed': datetime.fromtimestamp(stat.st_atime).isoformat(),
    }

    if os.path.isdir(file_path):
        try:
            contents = os.listdir(file_path)
            info['num_items'] = len(contents)
            # Calculate total size of directory
            total_size = 0
            for dirpath, dirnames, filenames in os.walk(file_path):
                for fname in filenames:
                    fp = os.path.join(dirpath, fname)
                    if os.path.isfile(fp):
                        total_size += os.path.getsize(fp)
            info['total_size_bytes'] = total_size
        except PermissionError:
            info['num_items'] = None
            info['total_size_bytes'] = None
    else:
        # Get file extension
        _, ext = os.path.splitext(file_path)
        info['extension'] = ext.lstrip('.') if ext else None

    # Clean up path display
    if info['path'] == '/.':
        info['path'] = '/'

    return info


@app.route('/api/files/list', methods=['GET'])
@require_user_id
def list_directory(user_id):
    """
    List contents of a directory.

    Query Parameters:
        - path: relative path to the directory (default: root '/')
        - user_id: user identifier (alternative to X-User-ID header)
        - show_hidden: whether to show hidden files (default: false)
        - sort_by: sort field - 'name', 'size', 'modified' (default: 'name')
        - sort_order: 'asc' or 'desc' (default: 'asc')
    """
    relative_path = request.args.get('path', '/')
    show_hidden = request.args.get('show_hidden', 'false').lower() == 'true'
    sort_by = request.args.get('sort_by', 'name')
    sort_order = request.args.get('sort_order', 'asc')

    user_root = get_user_root(user_id)
    full_path = resolve_path(user_root, relative_path)

    if full_path is None:
        return jsonify({'error': 'Invalid path. Directory traversal is not allowed.'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': f'Path not found: {relative_path}'}), 404

    if not os.path.isdir(full_path):
        return jsonify({'error': f'Path is not a directory: {relative_path}'}), 400

    try:
        entries = os.listdir(full_path)
    except PermissionError:
        return jsonify({'error': 'Permission denied.'}), 403

    items = []
    for entry_name in entries:
        # Skip hidden files if not requested
        if not show_hidden and entry_name.startswith('.'):
            continue

        entry_path = os.path.join(full_path, entry_name)
        try:
            stat = os.stat(entry_path)
            rel = os.path.relpath(entry_path, user_root)
            item = {
                'name': entry_name,
                'path': '/' + rel,
                'is_directory': os.path.isdir(entry_path),
                'size_bytes': stat.st_size if not os.path.isdir(entry_path) else None,
                'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
            }
            if not os.path.isdir(entry_path):
                _, ext = os.path.splitext(entry_name)
                item['extension'] = ext.lstrip('.') if ext else None
            items.append(item)
        except (OSError, PermissionError):
            # Skip entries we can't access
            continue

    # Sort items - directories first, then by specified field
    def sort_key(item):
        dir_priority = 0 if item['is_directory'] else 1
        if sort_by == 'size':
            return (dir_priority, item.get('size_bytes') or 0)
        elif sort_by == 'modified':
            return (dir_priority, item.get('modified', ''))
        else:  # name
            return (dir_priority, item['name'].lower())

    reverse = sort_order.lower() == 'desc'
    items.sort(key=sort_key, reverse=reverse)

    # Build current path info
    current_rel = os.path.relpath(full_path, user_root)
    current_path = '/' if current_rel == '.' else '/' + current_rel

    # Parent path
    if current_path == '/':
        parent_path = None
    else:
        parent = os.path.dirname(current_path.rstrip('/'))
        parent_path = parent if parent else '/'

    return jsonify({
        'success': True,
        'path': current_path,
        'parent_path': parent_path,
        'total_items': len(items),
        'items': items
    })


